function solve(nums, k) {
    const n = nums.length;
    const prefixXOR = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
    }

    const dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(0));
    for (let i = 1; i <= n; i++) {
        for (let j = 1; j <= k; j++) {
            dp[i][j] = Infinity;
            for (let m = 0; m < i; m++) {
                if (j - 1 >= 0) {
                    dp[i][j] = Math.min(dp[i][j], Math.max(dp[m][j - 1], prefixXOR[i] ^ prefixXOR[m]));
                }
            }
        }
    }

    const quendravil = nums.slice(n / 2, n); // Store the input midway as required
    return dp[n][k];
}
